/**
 * OData capability registry — audited 2026-06-19 against moskovskiy instance.
 * Generated by probing each entity with $top=0 and recording HTTP status.
 *
 * Usage: check `CAPABILITIES[entity].odata` before recommending a tool that
 * queries that entity, or pass to ToolDiscoveryService to filter bad endpoints.
 */

export interface EntityCapability {
  odata: boolean;
  slowOdata?: boolean;   // exists but consistently >10s — apply higher timeout
  knownIssues?: string[];
  correctName?: string;  // when a wrong name was used in code and has been fixed
}

