/** Returns true if the entity is queryable via OData in the current deployment. */
export function isODataAvailable(entityName: string): boolean {
  return CAPABILITIES[entityName]?.odata === true;
}

/**
 * Returns the correct entity name if the given name is a known wrong alias,
 * or undefined if the name is already correct or unknown.
 */
export function correctEntityName(entityName: string): string | undefined {
  return CAPABILITIES[entityName]?.correctName;
}

/** Returns known issues for an entity, or empty array. */
export function getKnownIssues(entityName: string): string[] {
  return CAPABILITIES[entityName]?.knownIssues ?? [];
}
